144	error_t ec_pve_batch_t::restore_from_decrypted(int row_index, mem_t decrypted_x_buf, ecurve_t curve,
145	                                               std::vector<bn_t>& x) const {
146	  if (row_index < 0 || row_index >= kappa) return coinbase::error(E_BADARG);
147	
148	  const mod_t& q = curve.order();
149	  const auto& G = curve.generator();
150	  int curve_size = curve.size();
151	
152	  const row_t& row = rows[row_index];
153	  const bool bi = b.get_bit(row_index);
154	
155	  mem_t r01;
156	  mem_t x1_bin;
157	  if (bi) {
158	    // When bi=1, the opened value is x1_bin (stored), and the unopened value is r01 (decrypted).
159	    if (row.x_bin.size() != n * curve_size) return coinbase::error(E_CRYPTO);
160	    x1_bin = row.x_bin;
161	    r01 = decrypted_x_buf;
162	    if (r01.size != 16) return coinbase::error(E_CRYPTO);
163	  } else {
164	    // When bi=0, the opened value is r01||r02 (stored in row.r), and the unopened value is x1_bin (decrypted).
165	    if (row.r.size() != 32) return coinbase::error(E_CRYPTO);
166	    r01 = row.r.take(16);
167	    x1_bin = decrypted_x_buf;
168	    if (x1_bin.size != n * curve_size) return coinbase::error(E_CRYPTO);
169	  }
170	
171	  crypto::drbg_aes_ctr_t drbg01(r01);
172	  buf_t x0_source_bin = drbg01.gen(n * (curve_size + coinbase::bits_to_bytes(SEC_P_STAT)));
173	  std::vector<bn_t> x0;
174	  error_t rv = bn_t::vector_from_bin(x0_source_bin, n, curve_size + coinbase::bits_to_bytes(SEC_P_STAT), q, x0);
175	  if (rv) return rv;
176	
177	  std::vector<bn_t> x1;
178	  rv = bn_t::vector_from_bin(x1_bin, n, curve_size, q, x1);
179	  if (rv) return rv;
180	
181	  for (int i = 0; i < n; i++) {
182	    MODULO(q) x[i] = x0[i] + x1[i];
183	    if (Q[i] != x[i] * G) return coinbase::error(E_CRYPTO);
184	  }
185	
186	  return SUCCESS;
187	}
188	
189	error_t ec_pve_batch_t::decrypt(const pve_base_pke_i& base_pke, pve_keyref_t dk, pve_keyref_t ek, mem_t label,
190	                                ecurve_t curve, std::vector<bn_t>& xs, bool skip_verify) const {
191	  error_t rv = UNINITIALIZED_ERROR;
192	  xs.resize(n);
193	  if (!skip_verify && (rv = verify(base_pke, ek, Q, label))) return rv;
194	
195	  if (label != this->L) return coinbase::error(E_CRYPTO);
196	  buf_t inner_label = genPVELabelWithPoint(label, Q);
197	
198	  for (int i = 0; i < kappa; i++) {
199	    buf_t x_buf;
200	    if (rv = base_pke.decrypt(dk, inner_label, rows[i].c, x_buf)) continue;
201	    if (restore_from_decrypted(i, x_buf, curve, xs) == SUCCESS) return SUCCESS;
202	  }
203	
204	  xs.clear();
205	  return coinbase::error(E_CRYPTO);
206	}
